// Slack slash commands POST application/x-www-form-urlencoded.
// n8n Webhook node parses form bodies into $json.body when content-type is form-urlencoded.
const body = $('Webhook — /intel').first().json.body || $('Webhook — /intel').first().json;
const text = (body.text || '').trim();
const response_url = body.response_url || null;
const user_name = body.user_name || 'unknown';

// Parse competitor name (case-insensitive match) + timeframe.
const competitors = ['Pigment','Anaplan','Planful','Drivetrain','Vena'];
let competitor_filter = null;
for (const c of competitors) {
  const re = new RegExp(`\\b${c}\\b`, 'i');
  if (re.test(text)) { competitor_filter = c; break; }
}

// Timeframe: 'last N days' | 'last N weeks' | 'last N months' | default 90 days
let days_back = 90;
const m = text.match(/last\s+(\d+)\s*(day|week|month)s?/i);
if (m) {
  const n = parseInt(m[1], 10);
  const unit = m[2].toLowerCase();
  days_back = unit === 'day' ? n : unit === 'week' ? n * 7 : n * 30;
}

// Build the embedding query: drop the parsed competitor + timeframe, keep the rest as semantic intent.
let semantic_query = text
  .replace(new RegExp(`\\b(${competitors.join('|')})\\b`, 'gi'), '')
  .replace(/last\s+\d+\s*(day|week|month)s?/gi, '')
  .replace(/\s+/g, ' ').trim();
if (!semantic_query) semantic_query = competitor_filter ? `recent intelligence about ${competitor_filter}` : 'recent competitive intelligence';

if (!response_url) {
  return [{ json: { _hard_error: 'missing_response_url', received: body } }];
}

return [{ json: { competitor_filter, days_back, semantic_query, response_url, user_name, raw_text: text } }];

