// Decide whether to short-circuit with an empty-result Slack message,
// or proceed to LLM synthesis.
const rag = Array.isArray($json) ? $json : ($json?.results || []);
const q = $('Code — parse query').first().json;
const hits = rag.filter(r => r && (r.content || '').length > 0);

if (hits.length === 0) {
  // Look up the most recent signal for this competitor (or any) to give the user a real anchor.
  const targetLabel = q.competitor_filter ? `**${q.competitor_filter}**` : 'any competitor';
  const text = `🔍 *No intelligence found for ${targetLabel} in last ${q.days_back} days.*\nTry a wider window — e.g. \`/intel ${q.competitor_filter || 'Pigment'} last 180 days\`.`;
  return [{ json: {
    short_circuit: true,
    response_url: q.response_url,
    slack_payload: {
      response_type: 'ephemeral',
      text,
      blocks: [
        { type: 'section', text: { type: 'mrkdwn', text } },
        { type: 'context', elements: [
          { type: 'mrkdwn', text: `_Query: \`${q.raw_text || '(empty)'}\`  ·  filter: ${q.competitor_filter || 'none'}  ·  window: ${q.days_back}d_` }
        ] }
      ]
    }
  } }];
}

return [{ json: { short_circuit: false, hits, query: q } }];

