    {
      "role": "user",
      "content": "<query>\n{{ $json.query.raw_text }}\n(filter: {{ $json.query.competitor_filter || 'all competitors' }} · window: last {{ $json.query.days_back }} days)\n</query>\n\n<retrieved_intel>\n{{ JSON.stringify($json.hits.map(h => ({competitor: h.competitor_name, type: h.signal_type, content: (h.content || '').slice(0, 600), source_url: h.source_url, scraped_at: h.scraped_at, similarity: Number(h.similarity || 0).toFixed(2)}))) }}\n</retrieved_intel>\n\nAnswer the query. Be specific about which competitor each fact belongs to. If the retrieved intel doesn't actually answer the question, say so and report what's available instead."
    }
  ]
}

