// Render the final Slack payload from Sonnet's answer + retrieved hits.
const llm = $json;
const upstream = $('Code — empty-result guard').first().json;
const q = upstream.query;
const hits = upstream.hits;

let answer;
try {
  answer = llm?.content?.[0]?.text || null;
  if (!answer) throw new Error('no_content');
} catch (e) {
  answer = '⚠️ Couldn\'t synthesise an answer right now (LLM error). Showing raw matches below.';
}

const headerText = `🔍 */intel ${q.competitor_filter || 'all'}* — last ${q.days_back} days`;
const sourcesContext = hits.slice(0, 3).map(h => `<${h.source_url || 'about:blank'}|${h.competitor_name} · ${h.signal_type} · ${(h.scraped_at || '').slice(0,10)}>`).join('  ·  ');

const slack_payload = {
  response_type: 'in_channel',
  text: headerText,
  blocks: [
    { type: 'section', text: { type: 'mrkdwn', text: `*${headerText}*\n${answer}` } },
    { type: 'context', elements: [
      { type: 'mrkdwn', text: `_Top sources: ${sourcesContext || '(none)'}_` },
      { type: 'mrkdwn', text: `_Asked by @${q.user_name}  ·  ${hits.length} hits  ·  query: \`${q.raw_text || '(empty)'}\`_` }
    ] }
  ]
};

return [{ json: { response_url: q.response_url, slack_payload } }];

